/// Defines a collection of widgets to display and modify the camera parameters.
library;

import 'dart:math';

// Flutter imports:
import 'package:flutter/material.dart';

// Project imports:
import './camera_configuration.dart';
import './camera_controller.dart';

String _formatModelName(dynamic value) {
  if (value == null) {
    return '';
  }

  final raw = value.toString();
  if (raw.isEmpty) {
    return raw;
  }

  final formatted = raw.replaceAllMapped(
    RegExp(r'(iPhone|iPad)'),
    (match) {
      final device = match.group(0)!;
      final needsLineBreak =
          match.end < raw.length && raw[match.end] != '\n';
      return needsLineBreak ? '$device\n' : device;
    },
  );

  return formatted;
}

