class _CameraValueItem extends StatelessWidget {
  final String label;
  final ValueNotifier notifier;
  final String Function(dynamic) formatter;
  final void Function()? onTap;

  const _CameraValueItem({
    required this.label,
    required this.notifier,
    required this.formatter,
    this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    const labelColor = Colors.white;
    const valueColor = Colors.white;
    const bgColor = Color.fromRGBO(0, 0, 0, 0.6);
    const borderRadius = BorderRadius.all(Radius.circular(12));
    const padding = EdgeInsets.symmetric(vertical: 8, horizontal: 8);
    final isTappable = onTap != null;
    final iconColor = isTappable ? Colors.amber : Colors.grey;
    final iconTooltip = isTappable ? 'Change setting' : null;
    final boxWidth = MediaQuery.of(context).orientation == Orientation.landscape
        ? MediaQuery.of(context).size.width * 0.35
        : MediaQuery.of(context).size.width * 0.5;

    return ValueListenableBuilder(
      valueListenable: notifier,
      builder: (context, value, _) {
        final body = Container(
          width: boxWidth,
          decoration: const BoxDecoration(
            color: bgColor,
            borderRadius: borderRadius,
          ),
          padding: padding,
          child: Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              SizedBox(
                width: boxWidth * 0.5,
                child: GestureDetector(
                  onTap: onTap,
                  child: Row(
                    children: [
                      Expanded(
                        child: Text(
                          label,
                          style: const TextStyle(
                            color: labelColor,
                            fontWeight: FontWeight.bold,
                            fontSize: 14,
                          ),
                          maxLines: 3,
                        ),
                      ),
                      if (isTappable) ...[
                        const SizedBox(width: 8),
                        Tooltip(
                          message: iconTooltip,
                          child: Padding(
                            padding: const EdgeInsets.only(left: 8.0),
                            child:
                                Icon(Icons.build, color: iconColor, size: 22),
                          ),
                        ),
                      ],
                    ],
                  ),
                ),
              ),
              SizedBox(
                width: boxWidth * 0.3,
                child: Text(
                  value != null ? formatter(value) : 'N/a',
                  style: const TextStyle(
                    color: valueColor,
                    fontWeight: FontWeight.bold,
                    fontSize: 14,
                  ),
                  textAlign: TextAlign.end,
                  maxLines: 3,
                ),
              )
            ],
          ),
        );

        return Padding(
          padding: const EdgeInsets.symmetric(vertical: 4, horizontal: 4),
          child: body,
        );
      },
    );
  }
}

class _SliderSettingDialog extends StatefulWidget {
  final double? value;
  final double? min;
  final double? max;
  final void Function(double) onChange;
  final int fixed;
  final String mappingType; // 'linear' or 'sqrt'

  const _SliderSettingDialog(
      {required this.value,
      required this.min,
      required this.max,
      required this.onChange,
      required this.fixed,
      this.mappingType = 'linear'});

  @override
  State<_SliderSettingDialog> createState() => _SliderSettingDialogState();

  static show(
      {required BuildContext context,
      required String title,
      required double? value,
      required double? min,
      required double? max,
      required void Function(double) onChange,
      required int fixed,
      String mappingType = 'linear'}) {
    showDialog(
      context: context,
      builder: (context) {
        return SimpleDialog(
          title: Text(title),
          children: <Widget>[
            _SliderSettingDialog(
                value: value,
                min: min,
                max: max,
                onChange: onChange,
                fixed: fixed,
                mappingType: mappingType)
          ],
        );
      },
    );
  }
}

class _SliderSettingDialogState extends State<_SliderSettingDialog> {
  double? value;
  double? sliderValue;

  @override
  void initState() {
    super.initState();
    value = widget.value;
    if (value != null && widget.min != null && widget.max != null) {
      sliderValue = _valueToSlider(value!);
    }
  }

  double _sliderToValue(double slider) {
    if (widget.mappingType == 'sqrt') {
      return widget.min! + (widget.max! - widget.min!) * (slider * slider);
    } else {
      return widget.min! + (widget.max! - widget.min!) * slider;
    }
  }

  double _valueToSlider(double value) {
    if (widget.mappingType == 'sqrt') {
      final norm = (value - widget.min!) / (widget.max! - widget.min!);
      return norm >= 0 ? sqrt(norm) : 0.0;
    } else {
      return (value - widget.min!) / (widget.max! - widget.min!);
    }
  }

  @override
  Widget build(BuildContext context) {
    return (sliderValue != null && widget.min != null && widget.max != null)
        ? Container(
            padding: const EdgeInsets.all(15),
            child: Column(children: [
              Align(
                alignment: Alignment.topLeft,
                child: Text(value?.toStringAsFixed(widget.fixed) ?? "N/a"),
              ),
              Align(
                  alignment: Alignment.topLeft,
                  child: Slider(
                    value: sliderValue!,
                    min: 0.0,
                    max: 1.0,
                    onChanged: (newSlider) {
                      final newValue = _sliderToValue(newSlider);
                      widget.onChange(newValue);
                      setState(() {
                        sliderValue = newSlider;
                        value = newValue;
                      });
                    },
                    onChangeEnd: (newSlider) {},
                  )),
            ]))
        : const Text("Notifiers not initialized.");
  }
}

