class _DropdownSettingDialogState extends State<_DropdownSettingDialog> {
  int? index;

  @override
  void initState() {
    super.initState();
    index = widget.index;
  }

  @override
  Widget build(BuildContext context) {
    return index != null && widget.list != null
        ? Container(
            padding: const EdgeInsets.all(15),
            child: Align(
              alignment: Alignment.topLeft,
              child: DropdownButton(
                isExpanded: true,
                value: widget.list![index!],
                icon: const Icon(Icons.arrow_drop_down_circle),
                items: widget.list!.map<DropdownMenuItem>((object) {
                  return DropdownMenuItem(
                    value: object,
                    child: Row(children: [
                      Text("${object.index}: "),
                      Text(widget.formatter(object))
                    ]),
                  );
                }).toList(),
                onChanged: (newValue) {
                  if (newValue != null) {
                    widget.onChange(newValue.index);
                    setState(() {
                      index = newValue.index;
                    });
                  }
                },
                hint: const Text("Select"),
              ),
            ),
          )
        : const Text("Notifiers not initialized.");
  }
}

_showLensDialog(BuildContext context, CameraController cameraController,
    CameraConfiguration cameraConfiguration) {
  _DropdownSettingDialog.show(
      context: context,
      title: "Lens",
      index: cameraConfiguration.lensIndex.value,
      list: cameraConfiguration.lensList.value,
      formatter: (lens) => lens.description,
      onChange: (newIndex) {
        cameraController.setLensIndex(newIndex);
      });
}

_showFormatDialog(BuildContext context, CameraController cameraController,
    CameraConfiguration cameraConfiguration) {
  _DropdownSettingDialog.show(
      context: context,
      title: "Format",
      index: cameraConfiguration.formatIndex.value,
      list: cameraConfiguration.formatList.value,
      formatter: (format) {
        final height = format.landscapeHeight;
        final width = format.landscapeWidth;
        final fps = format.fps;
        final fov = format.videoFieldOfView.toStringAsFixed(2);
        final options = <String>[];
        if (format.hdr) {
          options.add('hdr');
        }
        if (format.binned) {
          options.add('binned');
        }
        if (format.stabilization) {
          options.add('stbl.');
        }
        final description =
            "${height}x$width, ${fps}FPS\ndevice FoV $fov, ${options.join(', ')}";
        return description;
      },
      onChange: (newIndex) {
        cameraController.setFormatIndex(newIndex);
      });
}

