class _ToggleSettingDialogState extends State<_ToggleSettingDialog> {
  bool? value;

  @override
  void initState() {
    super.initState();
    value = widget.value;
  }

  @override
  Widget build(BuildContext context) {
    return value != null
        ? Container(
            padding: const EdgeInsets.all(15),
            child: Row(children: [
              Text(widget.falseLabel),
              Switch(
                value: value!,
                onChanged: (newValue) {
                  widget.onChange(newValue);
                  setState(() {
                    value = newValue;
                  });
                },
              ),
              Text(widget.trueLabel),
            ]),
          )
        : const Text("Notifiers not initialized.");
  }
}

